  // If authenticated, show role-based content with navigation
  return (
    <div className="min-h-screen bg-background flex flex-col">
      <Header />
      <main className="flex-1 overflow-y-auto pb-20">
        <Switch>
          <Route path="/" component={RoleBasedRedirect} />
